    // dp[i][j][k], where i is the length, j is the last value, k is the direction (0: down, 1: up)
    vector<vector<vector<long long>>> dp(n + 1, vector<vector<long long>>(m + 2, vector<long long>(2, 0)));

    // Initialize for length 2
    for (int j = 0; j < m; ++j) {
        dp[2][j][0] = m - 1;
        dp[2][j][1] = m - 1;
    }

    for (int i = 3; i <= n; ++i) {
        long long sum0 = 0, sum1 = 0;
        // Precompute prefix sums for direction 0 (down)
        for (int j = 0; j < m; ++j) {
            sum0 = (sum0 + dp[i-1][j][0]) % MOD;
        }
        // Precompute prefix sums for direction 1 (up)
        for (int j = 0; j < m; ++j) {
            sum1 = (sum1 + dp[i-1][j][1]) % MOD;
        }

        for (int j = 0; j < m; ++j) {
            // For direction 0 (down), previous step was up (1)
            dp[i][j][0] = (sum1 - dp[i-1][j][1] + MOD) % MOD;
            // For direction 1 (up), previous step was down (0)
            dp[i][j][1] = (sum0 - dp[i-1][j][0] + MOD) % MOD;
        }
    }

    long long ans = 0;
    for (int j = 0; j < m; ++j) {
        ans = (ans + dp[n][j][0] + dp[n][j][1]) % MOD;
    }
    return ans;
}
